"use client";

import Link from "next/link";
import { topics } from "@/data/topics";
import { useAuth } from "@/context/AuthContext";

interface NavbarProps {
  activeTopicId?: string;
}

export default function Navbar({ activeTopicId }: NavbarProps) {
  const { auth, logout } = useAuth();

  const displayName =
    auth?.type === "user" ? auth.name.split(" ")[0] : auth?.type === "guest" ? "ЧҗЧ•ЧЁЧ—" : null;

  return (
    <nav className="sticky top-0 z-50 bg-black border-b border-white/10">
      <div className="max-w-7xl mx-auto px-4">
        <div className="flex items-center justify-between h-14">
          <Link href="/" className="flex items-center gap-2.5 shrink-0 group">
            <span className="text-white font-bold text-xl" style={{ fontFamily: "serif", fontStyle: "italic" }}>
              вҲ‘
            </span>
            <span className="font-bold text-white text-sm md:text-base">
              Ч‘Ч’ЧЁЧ•ЧӘ ЧһЧӘЧһЧҳЧҷЧ§Ч” 5 ЧҷЧ—ЧҙЧң
            </span>
          </Link>

          <div className="hidden lg:flex items-center gap-0.5 overflow-x-auto">
            <Link
              href="/test"
              className="text-xs font-semibold whitespace-nowrap transition-colors px-3 py-1.5 bg-teal-500 text-white rounded-md hover:bg-teal-400 ml-1"
            >
              ЧһЧ‘Ч—Чҹ
            </Link>
            {topics.map((topic) => (
              <Link
                key={topic.id}
                href={`/topic/${topic.id}`}
                className={`text-xs font-medium whitespace-nowrap transition-colors px-2 py-1 ${
                  activeTopicId === topic.id
                    ? "text-white font-semibold underline underline-offset-4"
                    : "text-white/60 hover:text-white"
                }`}
              >
                <span>{topic.title}</span>
              </Link>
            ))}

            {/* User info + logout */}
            {displayName && (
              <div className="flex items-center gap-2 mr-3 border-r border-white/20 pr-3">
                <span className="text-white/50 text-xs">{displayName}</span>
                <button
                  onClick={logout}
                  className="text-xs text-white/40 hover:text-white transition-colors underline underline-offset-2"
                >
                  ЧҷЧҰЧҷЧҗЧ”
                </button>
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Mobile topic scroll */}
      <div className="lg:hidden border-t border-white/20 overflow-x-auto relative">
        <div className="pointer-events-none absolute inset-y-0 right-0 w-8 bg-gradient-to-l from-black to-transparent z-10" />
        <div className="flex gap-1 px-4 py-2 items-center">
          <Link
            href="/test"
            className="text-xs font-semibold whitespace-nowrap transition-colors px-3 py-1 bg-teal-500 text-white rounded-md hover:bg-teal-400"
          >
            ЧһЧ‘Ч—Чҹ
          </Link>
          {topics.map((topic) => (
            <Link
              key={topic.id}
              href={`/topic/${topic.id}`}
              className={`text-xs font-medium whitespace-nowrap transition-colors px-2 py-1 ${
                activeTopicId === topic.id
                  ? "text-white font-semibold underline underline-offset-4"
                  : "text-white/60 hover:text-white"
              }`}
            >
              <span>{topic.title}</span>
            </Link>
          ))}
          {displayName && (
            <button
              onClick={logout}
              className="text-xs text-white/40 hover:text-white transition-colors whitespace-nowrap mr-auto pr-2"
            >
              {displayName} В· ЧҷЧҰЧҷЧҗЧ”
            </button>
          )}
        </div>
      </div>
    </nav>
  );
}
